def route_query(user_input: str):
    # 1. Use cheap model to classify the intent
    intent = call_llm(user_input, model="gpt-4o-mini", system="Classify intent: SIMPLE or COMPLEX")

    if intent == "SIMPLE":
        # 2a. Route to cheap model
        return call_llm(user_input, model="gpt-4o-mini")
    else:
        # 2b. Route to expensive model
        return call_llm(user_input, model="gpt-4o")
